+bool AOTCacheAccess::can_generate_aot_code(address addr) {
+  assert(CDSConfig::is_dumping_final_static_archive(), "must be");
+  return ArchiveBuilder::is_active() && ArchiveBuilder::current()->has_been_archived(addr);
